// src/three/ModelLoader.js
// Handles loading and caching of 3D models

import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader';



window.testGLBModel('/assets/models/sBike-5.glb');

export class ModelLoader {
  constructor() {
    // Initialize the GLTF loader
    this.gltfLoader = new GLTFLoader();
    
    // Set up Draco loader for compressed models
    const dracoLoader = new DRACOLoader();
    dracoLoader.setDecoderPath('/draco/'); // Path to draco decoder (adjust if needed)
    this.gltfLoader.setDRACOLoader(dracoLoader);
    
    // Model cache to avoid reloading the same model
    this.modelCache = {};
    
    // Keep track of loading models
    this.loadingModels = {};
    
    // Use a LoadingManager to track loading progress
    this.loadingManager = new THREE.LoadingManager();
    this.loadingManager.onProgress = (url, loaded, total) => {
      // You can dispatch an event here to update a loading indicator
      const event = new CustomEvent('model-loading-progress', {
        detail: { url, loaded, total, progress: loaded / total }
      });
      window.dispatchEvent(event);
    };
    
    this.gltfLoader.manager = this.loadingManager;
  }

  load(modelType, modelPath, onLoad, onError) {
    // Check if model is already cached
    if (this.modelCache[modelType]) {
      console.log(`Using cached model: ${modelType}`);
      const clonedModel = this.cloneModel(this.modelCache[modelType]);
      if (onLoad) onLoad(clonedModel);
      return;
    }
    
    // Check if model is already being loaded
    if (this.loadingModels[modelType]) {
      console.log(`Model ${modelType} is already loading, waiting...`);
      this.loadingModels[modelType].callbacks.push(onLoad);
      return;
    }
    
    // Start loading the model
    console.log(`Loading model: ${modelType} from path: ${modelPath}`);
    
    // Track this loading operation
    this.loadingModels[modelType] = {
      callbacks: onLoad ? [onLoad] : []
    };
    
    // Dispatch loading started event
    const startEvent = new CustomEvent('model-loading-started', {
      detail: { modelType, modelPath }
    });
    window.dispatchEvent(startEvent);
    
    // Load the model using GLTFLoader
    this.gltfLoader.load(
      modelPath,
      (gltf) => {
        console.log(`Successfully loaded model: ${modelType}`, gltf);
        
        // Process the loaded model
        const model = this.processModel(gltf, modelType);
        
        // Cache the original model
        this.modelCache[modelType] = model.clone();
        
        // Call all registered callbacks with a clone of the model
        const callbacks = this.loadingModels[modelType].callbacks;
        callbacks.forEach(callback => {
          if (callback) callback(this.cloneModel(model));
        });
        
        // Cleanup
        delete this.loadingModels[modelType];
        
        // Dispatch loading completed event
        const completeEvent = new CustomEvent('model-loading-completed', {
          detail: { modelType, modelPath, model }
        });
        window.dispatchEvent(completeEvent);
      },
      (progress) => {
        // Progress callback
        console.log(`Loading progress for ${modelType}:`, progress);
      },
      (error) => {
        console.error(`Error loading model ${modelType}:`, error);
        
        // Call error callback if provided
        if (onError) onError(error);
        
        // Notify all waiting callbacks about the error
        const callbacks = this.loadingModels[modelType].callbacks;
        callbacks.forEach(callback => {
          if (callback) callback(this.createFallbackModel(modelType));
        });
        
        // Cleanup
        delete this.loadingModels[modelType];
        
        // Dispatch loading error event
        const errorEvent = new CustomEvent('model-loading-error', {
          detail: { modelType, modelPath, error }
        });
        window.dispatchEvent(errorEvent);
      }
    );
  }
  
  processModel(gltf, modelType) {
    const model = gltf.scene;
    
    // Add metadata to the model
    model.userData.type = modelType;
    model.userData.isModelRoot = true;
    model.userData.selectable = true;
    
    // Setup all materials in the model
    model.traverse((node) => {
      if (node.isMesh) {
        // Make sure materials are properly set up
        if (node.material) {
          // Enable shadows
          node.castShadow = true;
          node.receiveShadow = true;
          
          // Ensure material is properly initialized
          const materials = Array.isArray(node.material) ? node.material : [node.material];
          
          materials.forEach(material => {
            // Make sure material is visible
            material.transparent = material.transparent || false;
            material.opacity = material.opacity !== undefined ? material.opacity : 1.0;
            material.side = THREE.DoubleSide; // Show both sides of faces
            
            // Force material to update
            material.needsUpdate = true;
            
            // Fix potential uniform issue
            if (material.type === 'ShaderMaterial' || material.type === 'RawShaderMaterial') {
              if (material.uniforms) {
                Object.keys(material.uniforms).forEach(key => {
                  if (material.uniforms[key] === undefined) {
                    material.uniforms[key] = { value: null };
                  } else if (material.uniforms[key].value === undefined) {
                    material.uniforms[key].value = null;
                  }
                });
              }
            }
          });
        }
      }
    });
    
    // Center model on its base
    this.centerModel(model);
    
    return model;
  }
  
  centerModel(model) {
    // Compute bounding box
    const box = new THREE.Box3().setFromObject(model);
    const center = box.getCenter(new THREE.Vector3());
    const size = box.getSize(new THREE.Vector3());
    
    // Calculate offset to place model on the ground
    const yOffset = size.y / 2;
    
    // Center horizontally but place on ground
    model.position.x = -center.x;
    model.position.z = -center.z;
    model.position.y = -center.y + yOffset;
    
    return model;
  }
  
  cloneModel(original) {
    // Create a deep clone of the model
    const clone = original.clone();
    
    // Clone materials to avoid shared material issues
    clone.traverse((node) => {
      if (node.isMesh && node.material) {
        // Handle both single materials and arrays
        if (Array.isArray(node.material)) {
          node.material = node.material.map(mat => mat.clone());
        } else {
          node.material = node.material.clone();
        }
      }
    });
    
    // Copy user data
    clone.userData = JSON.parse(JSON.stringify(original.userData));
    
    return clone;
  }
  
  createFallbackModel(modelType) {
    console.warn(`Creating fallback model for: ${modelType}`);
    
    // Create a simple box as fallback
    const geometry = new THREE.BoxGeometry(1, 1, 1);
    const material = new THREE.MeshStandardMaterial({ 
      color: 0x888888,
      transparent: true,
      opacity: 0.7
    });
    
    const mesh = new THREE.Mesh(geometry, material);
    
    // Create a group to hold the mesh (similar structure to loaded models)
    const group = new THREE.Group();
    group.add(mesh);
    
    // Add metadata
    group.userData.type = modelType;
    group.userData.isModelRoot = true;
    group.userData.selectable = true;
    group.userData.isFallback = true;
    
    return group;
  }
  
  duplicate(originalObject, onComplete) {
    const modelType = originalObject.userData.type;
    
    if (this.modelCache[modelType]) {
      // If we have the model in cache, clone it
      const clone = this.cloneModel(this.modelCache[modelType]);
      
      // Copy transformation from original
      clone.position.copy(originalObject.position);
      clone.rotation.copy(originalObject.rotation);
      clone.scale.copy(originalObject.scale);
      
      if (onComplete) onComplete(clone);
    } else {
      // If not in cache, create a fallback and log warning
      console.warn(`Cannot duplicate model ${modelType}: not found in cache`);
      const fallback = this.createFallbackModel(modelType);
      
      // Copy transformation from original
      fallback.position.copy(originalObject.position);
      fallback.rotation.copy(originalObject.rotation);
      fallback.scale.copy(originalObject.scale);
      
      if (onComplete) onComplete(fallback);
    }
  }
}
